// Dockerfile HEALTHCHECK:
// HEALTHCHECK --interval=30s --timeout=10s --start-period=60s --retries=3 \
//   CMD wget -qO- http://localhost:8080/actuator/health | grep '"status":"UP"' || exit 1

// docker-compose.yml healthcheck:
// healthcheck:
//   test: ['CMD','wget','-qO-','http://localhost:8080/actuator/health']
//   interval: 30s
//   timeout: 10s
//   retries: 3
//   start_period: 60s   # give Spring Boot time to start before first check

// application.yml:
// management.endpoint.health.show-details: always
// management.endpoint.health.probes.enabled: true  # k8s readiness/liveness probes

@Component("dbHealth")
class PaymentDbHealthIndicator implements HealthIndicator {
    @Override public Health health() {
        return Health.up().withDetail("db","postgresql").build();
    }
}

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
class HealthEndpointTest {
    @Autowired WebTestClient webClient;

    @Test void healthEndpoint_returnsUp() {
        webClient.get().uri("/actuator/health")
            .exchange()
            .expectStatus().isOk()
            .expectBody()
            .jsonPath("$.status").isEqualTo("UP");
    }
}

// ZERO-DOWNTIME RESTART:
// 1. New container starts (status: starting)
// 2. Docker runs healthcheck every 30s
// 3. After healthcheck passes: status = healthy
// 4. Kubernetes/Docker Swarm: only sends traffic to healthy containers
// 5. Old container: gracefully stopped after new one is healthy
// Result: no request lost during deployment

// OOMKilled DIAGNOSIS AND FIX:

// Step 1: Confirm OOMKilled:
// $ docker inspect <container_id> | grep OOMKilled
//   'OOMKilled': true

// Step 2: Check JVM heap vs container limit:
// (While app is running, if it hasn't crashed yet)
// $ docker exec <container> java -XX:+PrintFlagsFinal -version 2>&1 | grep -i maxheap
// Or: check the actuator metrics:
// GET /actuator/metrics/jvm.memory.max  → check heap max value
// If jvm.memory.max > container_limit: OOMKilled is certain

// Step 3: Root cause
// Container limit: 256m = 268,435,456 bytes
// Without MaxRAMPercentage: JVM reads host RAM (e.g., 16GB) → allocates 4GB heap!
// 4GB heap in 256m container → OOMKilled immediately
// With MaxRAMPercentage=75: heap = 256 × 0.75 = 192MB → safe

// Step 4: Maximum heap for 256m container:
// MaxRAMPercentage=75: heap = 192MB
// Remaining 25% (64MB) for: Metaspace + thread stacks + JIT + GC overhead
// 64MB non-heap: works for small services (few classes, few threads)
// If Metaspace grows beyond 64MB: adjust to 512m container

// Step 5: Fixed docker-compose.yml:
// services:
//   app:
//     deploy:
//       resources:
//         limits:
//           memory: 256m
//     environment:
//       JAVA_TOOL_OPTIONS: >-
//         -XX:MaxRAMPercentage=75.0
//         -XX:+UseContainerSupport
//         -XX:MaxMetaspaceSize=64m
//         -Xss256k   (reduce stack size if many threads)

// Rule of thumb for 256m:
// -XX:MaxRAMPercentage=70 → heap = 179MB (safer, leaves more for non-heap)
// -XX:MaxMetaspaceSize=64m → cap Metaspace growth

public class OOMDiagnosis { public static void main(String[] a) {
    System.out.println("OOMKilled: heap set to host RAM not container limit");
    System.out.println("Fix: -XX:MaxRAMPercentage=75 + -XX:+UseContainerSupport");} }

