import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.test.web.reactive.server.WebTestClient;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.RANDOM_PORT)
class DockerReadinessTest {
    @Autowired WebTestClient wc;
    @Autowired MeterRegistry reg;

    @Test void healthEndpoint_returnsUp() {
        wc.get().uri("/actuator/health")
          .exchange()
          .expectStatus().isOk()
          .expectBody().jsonPath("$.status").isEqualTo("UP");
    }

    @Test void metricsEndpoint_available() {
        wc.get().uri("/actuator/prometheus")
          .exchange()
          .expectStatus().isOk()
          .expectBody(String.class)
          .value(body -> assertTrue(body.contains("jvm_memory")));
    }

    @Test void customCounter_registers() {
        Counter c = reg.counter("synthesis.test.counter", "phase", "m21t1");
        c.increment();
        assertEquals(1.0, c.count(), 0.01);
    }
}
